INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (155, "人助けが大好き！　前向き格闘娘", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "東山奈央", 8, 27, "A", "獣人族", 100101, "人助け、応援", 16, 44, 0, "トゥインクルウィッシュ", 2, "ヒヨリ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "戦闘のサポートが得意な、心優しい少女", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "種田梨沙", 4, 5, "O", "ヒューマン", 100201, "料理、人間観察", 17, 47, 0, "トゥインクルウィッシュ", 2, "ユイ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "クールで何事にも真っ直ぐな剣士", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "早見沙織", 1, 12, "B", "魔族", 100301, "読書、乗馬、お茶", 18, 46, 0, "トゥインクルウィッシュ", 2, "レイ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (128, "探検好きのイタズラっ子", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "諸星すみれ", 8, 10, "O", "ヒューマン", 100401, "いたずら、探検", 9, 27, 0, "リトルリリカル", 5, "ミソギ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (146, "ヒーローに憧れる騎士見習いの少女", "？？？", "下田麻美", 11, 25, "O", "獣人族", 100501, "ヒーローごっこ", 12, 40, 0, "王宮騎士団（NIGHTMARE）", 8, "マツリ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "甘え上手なみんなの人気者", "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "浅倉杏美", 11, 22, "O", "魔族", 100601, "サックス", 13, 42, 0, "悪魔偽王国軍（ディアボロス）", 7, "アカリ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (130, "プリン大好きゴースト娘", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "雨宮天", 1, 23, "B", "魔族", 100701, "プリンを食べること", 14, 32, 0, "悪魔偽王国軍（ディアボロス）", 7, "ミヤコ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "ボクは誰よりも美しい", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "大空直美", 10, 10, "AB", "エルフ", 100801, "鏡で自分を見ること", 14, 40, 0, "ヴァイスフリューゲル　ランドソル支部", 15, "ユキ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (159, "前世を信じる中二病患者、「疾風の冥姫」", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "髙野麻美", 7, 5, "A", "魔族", 100901, "小説執筆", 17, 45, 0, "トワイライトキャラバン", 13, "アンナ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (155, "マホマホ王国のプリンセス", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "内田真礼", 9, 22, "O", "獣人族", 101001, "空想、ぬいぐるみ集め", 16, 42, 0, "自警団（カォン）", 10, "マホ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "人懐っこくてマシンガントークな妹系少女", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "阿澄佳奈", 8, 25, "A", "ヒューマン", 101101, "お裁縫", 15, 44, 0, "ラビリンス", 3, "リノ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "みんなのために超能力を使う眠り姫", "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "大橋彩香", 12, 24, "A", "エルフ", 101201, "妹と遊ぶこと、二度寝、昼寝、早寝", 17, 46, 0, "フォレスティエ", 6, "ハツネ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (166, "オタク全開な魔法少女", "", "佳村はるか", 8, 21, "O", "魔族", 101301, "読書、魔法", 18, 55, 0, "トワイライトキャラバン", 13, "ナナカ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (152, "頭脳明晰な美少女名探偵", "test", "水瀬いのり", 11, 3, "AB", "獣人族", 101401, "読書、推理", 15, 41, 0, "自警団（カォン）", 10, "カスミ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (165, "母性溢れる優しいみんなの「ミサト先生」", "test", "國府田マリ子", 9, 5, "O", "エルフ", 101501, "絵本作り", 21, 54, 0, "フォレスティエ", 6, "ミサト");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (167, "天真爛漫で人気者のカリスマモデル", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "上坂すみれ", 4, 10, "O", "魔族", 101601, "ファッション", 17, 48, 0, "ルーセント学院", 14, "スズナ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "いつでも「なんくるないさ～」な天然娘", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "高森奈津美", 7, 7, "A", "獣人族", 101701, "踊り、空手", 17, 53, 0, "自警団（カォン）", 10, "カオリ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (162, "多くの男性を魅了する無垢な女教師", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "伊藤静", 8, 14, "B", "魔族", 101801, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 23, 52, 0, "ルーセント学院", 14, "イオ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (117, "お歌もにんじんも、ウサギさんも大好き♪", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "日高里菜", 4, 3, "O", "獣人族", 102001, "かわいいもの集め", 10, 21, 0, "リトルリリカル", 5, "ミミ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "泣き虫で臆病な守ってあげたい女の子", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "植田佳奈", 6, 9, "B", "ヒューマン", 102101, "観劇、おままごと", 12, 40, 0, "サレンディア救護院", 9, "クルミ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "人見知りであまのじゃくな女の子", "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "原紗友里", 11, 22, "O", "魔族", 102201, "ゲーム全般", 13, 40, 0, "悪魔偽王国軍（ディアボロス）", 7, "ヨリ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (148, "ぷうきちといつも一緒！", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "芹澤優", 5, 10, "B", "ヒューマン", 102301, "屋内でできる遊び", 14, 38, 0, "サレンディア救護院", 9, "アヤネ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (154, "お嬢さまのためにがんばるドジっ娘メイド", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "悠木碧", 12, 12, "O", "ヒューマン", 102501, "ご奉仕", 15, 43, 0, "サレンディア救護院", 9, "スズメ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (144, "遊びと睡眠が何より大事なぐうたら娘", "test", "小岩井ことり", 1, 1, "B", "獣人族", 102601, "あんパン", 17, 42, 0, "牧場（エリザベスパーク）", 11, "リン");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (154, "運命の相手に一途すぎる乙女", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "橋本ちなみ", 7, 30, "B", "魔族", 102701, "実験、裁縫、料理", 16, 43, 0, "トワイライトキャラバン", 13, "エリコ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "救護院を経営する優しい庶民派お嬢様", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "堀江由衣", 10, 4, "A", "エルフ", 102801, "経営、お茶会", 17, 43, 0, "サレンディア救護院", 9, "サレン");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "歌って踊れる大人気アイドル", "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", "日笠陽子", 1, 24, "B", "ヒューマン", 102901, "舞台鑑賞、ダンス", 17, 40, 0, "カルミナ", 4, "ノゾミ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "トーゴクの神秘、オシエテクダサイ！", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "佐藤聡美", 8, 31, "O", "ヒューマン", 103001, "忍法開発", 16, 51, 0, "ヴァイスフリューゲル　ランドソル支部", 15, "ニノン");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "占いが得意な霊能少女", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "大坪由佳", 12, 22, "AB", "魔族", 103101, "占い", 18, 42, 0, "悪魔偽王国軍（ディアボロス）", 7, "シノブ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "一人前の商人を目指すパワフルお嬢様", "この私とともにいる限り、\nお金に不自由はさせませんわ！", "松嵜麗", 3, 12, "AB", "ヒューマン", 103201, "慈善事業", 18, 45, 0, "メルクリウス財団", 12, "アキノ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (142, "みんなを笑顔にするお笑い牧場主", "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "新田恵海", 3, 3, "B", "ヒューマン", 103301, "漫才", 20, 35, 0, "牧場（エリザベスパーク）", 11, "マヒル");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (164, "純情でほっとけない大人の女性", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "今井麻美", 3, 16, "A", "エルフ", 103401, "ウインドーショッピング", 22, 55, 0, "メルクリウス財団", 12, "ユカリ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (118, "礼儀正しくしっかり者のちびっ子優等生", "test", "小倉唯", 2, 2, "A", "エルフ", 103601, "お勉強", 8, 21, 0, "リトルリリカル", 5, "キョウカ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (149, "義理堅くてからかい好きな剣術少女", "test", "茅原実里", 8, 11, "A", "ヒューマン", 103701, "剣術、年長者をからかう", 13, 43, 0, "王宮騎士団（NIGHTMARE）", 8, "トモ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (153, "読書が趣味の病弱少女", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "小清水亜美", 11, 3, "A", "獣人族", 103801, "読書、お散歩", 14, 40, 0, "牧場（エリザベスパーク）", 11, "シオリ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "「友達」に憧れる、エルフの森の女の子", "友達ができるその日まで…\nBB団で\nトレーニングですっ！", "花澤香菜", 6, 6, "AB", "エルフ", 104001, "友達作りのイメトレ", 13, 44, 0, "フォレスティエ", 6, "アオイ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "人々を守るために歌う、唱喚士の少女", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "福原綾香", 6, 3, "O", "ヒューマン", 104201, "各種楽器", 17, 46, 0, "カルミナ", 4, "チカ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (168, "男勝りで情に厚いワイルド娘", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "小松未可子", 8, 9, "O", "獣人族", 104301, "お菓子作り", 17, 54, 0, "自警団（カォン）", 10, "マコト");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (172, "かつては夜を支配した最強の吸血鬼", "test", "丹下桜", 5, 5, "A", "魔族", 104401, "世界征服", "??", 50, 0, "悪魔偽王国軍（ディアボロス）", 7, "イリヤ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "妄想大好き！　ほんとは照れ屋な女の子", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "長妻樹里", 11, 19, "AB", "ヒューマン", 104501, "小説を読むこと", 18, 49, 0, "ヴァイスフリューゲル　ランドソル支部", 15, "クウカ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "弱きを助け強きをくじく猫娘", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "沼倉愛美", 3, 1, "AB", "獣人族", 104601, "猫とたわむれること", 19, 48, 0, "メルクリウス財団", 12, "タマキ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (171, "素顔を見せない冷静沈着な女性騎士", "？？？", "川澄綾子", 10, 25, "A", "ヒューマン", 104701, "格闘技、湯浴み", 25, 50, 0, "王宮騎士団（NIGHTMARE）", 8, "ジュン");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "仕事も私事も効率優先な傭兵少女", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "田所あずさ", 11, 11, "O", "ヒューマン", 104801, "傭兵などのアルバイト", 20, 49, 0, "メルクリウス財団", 12, "ミフユ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (168, "お姉ちゃんがお世話してあげるからねっ！", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "生天目仁美", 10, 24, "O", "ヒューマン", 104901, "家事全般", 18, 54, 0, "ラビリンス", 3, "シズル");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (120, "ちょっとおませな恋に恋する女の子", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "久野美咲", 1, 3, "A", "魔族", 105001, "ファッション誌鑑賞、コスメ集め", 11, 22, 0, "ルーセント学院", 14, "ミサキ");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (166, "実験が趣味の危険な科学者", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "三石琴乃", 3, 7, "A", "ヒューマン", 105101, "研究、実験", 27, 53, 0, "トワイライトキャラバン", 13, "ミツキ");
