INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "弱きを助け強きをくじく猫娘", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "沼倉愛美", 3, 1, "AB", "獣人族", 107901, "猫とたわむれること", 19, 48, 0, "メルクリウス財団", 12, "タマキ（サマー）");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "仕事も私事も効率優先な傭兵少女", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "田所あずさ", 11, 11, "O", "ヒューマン", 108001, "傭兵などのアルバイト", 20, 49, 0, "メルクリウス財団", 12, "ミフユ（サマー）");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "占いが得意な霊能少女", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "大坪由佳", 12, 22, "AB", "魔族", 108101, "占い", 18, 42, 0, "悪魔偽王国軍（ディアボロス）", 7, "シノブ（ハロウィン）");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (130, "プリン大好きゴースト娘", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "雨宮天", 1, 23, "B", "魔族", 108201, "プリンを食べること", 14, 32, 0, "悪魔偽王国軍（ディアボロス）", 7, "ミヤコ（ハロウィン）");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (120, "ちょっとおませな恋に恋する女の子", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "久野美咲", 1, 3, "A", "魔族", 108301, "ファッション誌鑑賞、コスメ集め", 11, 22, 0, "ルーセント学院", 14, "ミサキ（ハロウィン）");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "人々を守るために歌う、唱喚士の少女", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "福原綾香", 6, 3, "O", "ヒューマン", 108401, "各種楽器", 17, 46, 0, "カルミナ", 4, "チカ（クリスマス）");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "泣き虫で臆病な守ってあげたい女の子", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "植田佳奈", 6, 9, "B", "ヒューマン", 108501, "観劇、おままごと", 12, 40, 0, "サレンディア救護院", 9, "クルミ（クリスマス）");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (148, "ぷうきちといつも一緒！", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "芹澤優", 5, 10, "B", "ヒューマン", 108601, "屋内でできる遊び", 14, 38, 0, "サレンディア救護院", 9, "アヤネ（クリスマス）");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (155, "人助けが大好き！　前向き格闘娘", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "東山奈央", 8, 27, "A", "獣人族", 108701, "人助け、応援", 16, 44, 0, "トゥインクルウィッシュ", 2, "ヒヨリ（ニューイヤー）");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "戦闘のサポートが得意な、心優しい少女", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "種田梨沙", 4, 5, "O", "ヒューマン", 108801, "料理、人間観察", 17, 47, 0, "トゥインクルウィッシュ", 2, "ユイ（ニューイヤー）");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "クールで何事にも真っ直ぐな剣士", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "早見沙織", 1, 12, "B", "魔族", 108901, "読書、乗馬、お茶", 18, 46, 0, "トゥインクルウィッシュ", 2, "レイ（ニューイヤー）");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (154, "運命の相手に一途すぎる乙女", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "橋本ちなみ", 7, 30, "B", "魔族", 109001, "実験、裁縫、料理", 16, 43, 0, "トワイライトキャラバン", 13, "エリコ（バレンタイン）");
