INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "ボクは誰よりも美しい", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "大空直美", 10, 10, "AB", "エルフ", 117601, "鏡で自分を見ること", 14, 40, 0, "ヴァイスフリューゲル　ランドソル支部", 15, "ユキ（オーエド）");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "いつでも「なんくるないさ～」な天然娘", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "高森奈津美", 7, 7, "A", "獣人族", 117701, "踊り、空手", 17, 53, 0, "自警団（カォン）", 10, "カオリ（ハロウィン）");
