INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (159, "前世を信じる中二病患者、「疾風の冥姫」", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "髙野麻美", 7, 5, "A", "魔族", 121901, "小説執筆", 17, 45, 0, "トワイライトキャラバン", 13, "アンナ（パイレーツ）");
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "占いが得意な霊能少女", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "大坪由佳", 12, 22, "AB", "魔族", 122001, "占い", 18, 42, 0, "悪魔偽王国軍（ディアボロス）", 7, "シノブ（パイレーツ）");
