INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (164, "純情でほっとけない大人の女性", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "今井麻美", 3, 16, "A", "エルフ", 122201, "ウインドーショッピング", 22, 55, 0, "メルクリウス財団", 12, "ユカリ（キャンプ）");
